// // This SRAM cell has a data input (D), a data output (Q), a write disable signal (WD), a read disable signal (RD), and a clock signal (CLK). When WD is low, the input data D should be written into the SRAM cell. When RD is low, the data stored in the SRAM cell should be output to Q on the falling edge of the clock.
module SRAM_Cell (  
    input wire [15:0] D,  
    output reg [15:0] Q,  
    input wire WE,  
    input wire RE,  
    input wire CLK  
);  
    reg [15:0] memory;  

    always @(posedge CLK) begin  
        if (WE) begin  
            memory <= D;  
        end  
        if (RE) begin  
            Q <= memory;  
        end  
    end  
endmodule
